import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './App.css'; // Kết nối file CSS ở trên

function App() {
    const [employees, setEmployees] = useState([]);

    // Gọi dữ liệu từ Backend Java của Thái
    useEffect(() => {
        axios.get("http://localhost:8080/api/employees")
            .then(response => {
                setEmployees(response.data);
            })
            .catch(error => {
                console.error("Lỗi kết nối Backend:", error);
            });
    }, []);

    return (
        <div className="container">
            <h1>HỆ THỐNG QUẢN LÝ NHÂN SỰ PTIT</h1>

            <table className="styled-table">
                <thead>
                <tr>
                    <th>ID</th>
                    <th>Họ và Tên</th>
                    <th>Phòng ban</th>
                    <th>Chức vụ</th>
                </tr>
                </thead>
                <tbody>
                {employees.length > 0 ? (
                    employees.map(emp => (
                        <tr key={emp.id}>
                            <td>{emp.id}</td>
                            <td style={{ fontWeight: "600", color: "#333" }}>{emp.fullName}</td>
                            <td>{emp.department}</td>
                            <td>{emp.position}</td>
                        </tr>
                    ))
                ) : (
                    <tr>
                        <td colSpan="4" style={{ textAlign: "center" }}>Đang tải dữ liệu hoặc chưa có nhân viên nào...</td>
                    </tr>
                )}
                </tbody>
            </table>
        </div>
    );
}

export default App;
